267: const getMainFrames = (frames: DataFrame[] | null) => {
268:   return frames?.filter((df) => df.meta?.custom?.parentRowIndex === undefined) || [frames?.[0]];
269: };
270: 
271: /**
272:  * In 9.3 meta.custom.parentRowIndex was introduced to support sub-tables.
273:  * In 10.2 meta.custom.parentRowIndex was deprecated in favor of FieldType.nestedFrames, which supports multiple nested frames.
274:  * Migrate DataFrame[] from using meta.custom.parentRowIndex to using FieldType.nestedFrames
275:  */
276: export const migrateFromParentRowIndexToNestedFrames = (frames: DataFrame[] | null) => {
277:   const migratedFrames: DataFrame[] = [];
278:   const mainFrames = getMainFrames(frames).filter(
279:     (frame: DataFrame | undefined): frame is DataFrame => !!frame && frame.length !== 0
280:   );
281: 
282:   mainFrames?.forEach((frame) => {
283:     const subFrames = frames?.filter((df) => frame.refId === df.refId && df.meta?.custom?.parentRowIndex !== undefined);
284:     const subFramesGrouped = groupBy(subFrames, (frame: DataFrame) => frame.meta?.custom?.parentRowIndex);
285:     const subFramesByIndex = Object.keys(subFramesGrouped).map((key) => subFramesGrouped[key]);
286:     const migratedFrame = { ...frame };
287: 
288:     if (subFrames && subFrames.length > 0) {
289:       migratedFrame.fields.push({
290:         name: 'nested',
291:         type: FieldType.nestedFrames,
292:         config: {},
293:         values: subFramesByIndex,
294:       });
295:     }
296:     migratedFrames.push(migratedFrame);
297:   });
298: 
299:   return migratedFrames;
300: };
301: 
302: export const hasDeprecatedParentRowIndex = (frames: DataFrame[] | null) => {
303:   return frames?.some((df) => df.meta?.custom?.parentRowIndex !== undefined);
304: };
305: 
306: export const migrateTextWrapToFieldLevel = (panel: PanelModel<Partial<Options>>) => {
307:   if (panel.fieldConfig?.defaults.custom?.wrapText !== undefined) {
308:     // already migrated
309:     return;
310:   }
311: 
312:   const legacyDefaultWrapText: boolean | undefined = panel.fieldConfig?.defaults.custom?.cellOptions?.wrapText;
313: 
314:   panel.fieldConfig.overrides = panel.fieldConfig.overrides.map((override) => {
315:     if (override.properties) {
316:       override.properties = override.properties.flatMap((property) => {
317:         if (property.id === 'custom.cellOptions' && property.value && property.value.wrapText !== undefined) {
318:           return [
319:             { ...property, value: { ...omit(property.value, 'wrapText') } },
320:             { id: 'custom.wrapText', value: property.value.wrapText },
321:           ];
322:         }
323:         return [property];
324:       });
325:     }
326:     return override;
327:   });
328: 
329:   panel.fieldConfig.defaults.custom = panel.fieldConfig.defaults.custom ?? {};
330:   panel.fieldConfig.defaults.custom.wrapText = legacyDefaultWrapText;
331:   delete panel.fieldConfig.defaults.custom.cellOptions?.wrapText;
332: 
333:   return panel;
334: };
335: 
336: export const migrateHiddenFields = (panel: PanelModel<Partial<Options>>) => {
337:   panel.fieldConfig.overrides = panel.fieldConfig.overrides.map((override) => {
338:     if (override.properties) {
339:       override.properties = override.properties.map((property) => {
340:         if (property.id === 'custom.hidden') {
341:           return { ...property, id: 'custom.hideFrom.viz' };
342:         }
343:         return property;
344:       });
345:     }
346:     return override;
347:   });
348: 
349:   return panel;
350: };
