1069: // cleanupFieldConfigDefaults removes properties that frontend considers as defaults and omits
1070: func cleanupFieldConfigDefaults(defaults map[string]interface{}, panel map[string]interface{}) {
1071: 	// Don't remove mappings, color objects, or unit properties - frontend preserves them
