2464: function createRow(options: any, panelDescriptions: any[]) {
2465:   const PANEL_HEIGHT_STEP = GRID_CELL_HEIGHT + GRID_CELL_VMARGIN;
2466:   const { collapse, showTitle, title, repeat, repeatIteration } = options;
2467:   let { height } = options;
2468:   height = height * PANEL_HEIGHT_STEP;
2469:   const panels: any[] = [];
2470:   each(panelDescriptions, (panelDesc) => {
2471:     const panel = { span: panelDesc[0] };
2472:     if (panelDesc.length > 1) {
2473:       //@ts-ignore
2474:       panel['height'] = panelDesc[1] * PANEL_HEIGHT_STEP;
2475:     }
2476:     panels.push(panel);
2477:   });
2478:   const row = {
2479:     collapse,
2480:     height,
2481:     showTitle,
2482:     title,
2483:     panels,
2484:     repeat,
2485:     repeatIteration,
2486:   };
2487:   return row;
2488: }
